// ─── COURSE MANAGEMENT ────────────────────────────────────────────────────────
export const AdminCourses = () => {
  const [courses, setCourses]   = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [depts, setDepts]       = useState([]);
  const [modal, setModal]       = useState(false);
  const [loading, setLoading]   = useState(false);
  const [form, setForm]         = useState({ title: "", description: "", department: "", durationHours: "", teacherId: "" });

  useEffect(() => {
    setLoading(true);
    Promise.all([getAllCourses(), getAllTeachers(), getAllDepartments()])
      .then(([c, t, d]) => { setCourses(Array.isArray(c) ? c : []); setTeachers(Array.isArray(t) ? t : []); setDepts(Array.isArray(d) ? d.filter(x => x.active) : []); })
      .catch(console.error).finally(() => setLoading(false));
  }, []);

  const handleCreate = async () => {
    try {
      const created = await createCourse({ ...form, durationHours: Number(form.durationHours) || 0, teacherId: form.teacherId ? Number(form.teacherId) : undefined });
      setCourses(c => [...c, created]);
      setModal(false);
      setForm({ title: "", description: "", department: "", durationHours: "", teacherId: "" });
    } catch (err) { alert("Error: " + err.message); }
  };

  const handleDelete = async (id) => {
    if (!confirmAction("Delete this course?")) return;
    await deleteCourse(id).catch(console.error);
    setCourses(c => c.filter(x => x.id !== id));
  };

  const rows = courses.map(c => [
    <div><div style={{ fontWeight: 700 }}>{c.title}</div><div style={{ fontSize: 11, color: T.muted }}>{c.durationHours} hrs</div></div>,
    c.teacher?.name || "—", c.department || "—", c.enrolledCount ?? "—",
    <Badge type={c.status === "ACTIVE" ? "success" : "warning"}>{c.status || "DRAFT"}</Badge>,
    <Btn size="xs" variant="danger" onClick={() => handleDelete(c.id)}>Del</Btn>,
  ]);

  return (
    <div className="fade-up">
      <PageHeader title="Course Management" subtitle="Create, manage and assign courses to teachers"
        actions={[<Btn variant="primary" onClick={() => setModal(true)}>+ Create Course</Btn>]} />
      <Card>
        {loading ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
          : <Table columns={["Course", "Teacher", "Department", "Students", "Status", "Actions"]} rows={rows.length ? rows : [["No courses", "", "", "", "", ""]]} />}
      </Card>
      <Modal open={modal} onClose={() => setModal(false)} title="Create New Course">
        <Input label="Course Name *"      placeholder="e.g. Full Stack Development" value={form.title}         onChange={e => setForm(f => ({ ...f, title: e.target.value }))} />
        <Input label="Duration (hours) *" placeholder="e.g. 120"                   value={form.durationHours} onChange={e => setForm(f => ({ ...f, durationHours: e.target.value }))} />
        <Input label="Description"        placeholder="Brief description"           value={form.description}   onChange={e => setForm(f => ({ ...f, description: e.target.value }))} />
        {/* Department dropdown from DB */}
        <Select label="Department *" value={form.department} onChange={e => setForm(f => ({ ...f, department: e.target.value }))}
          options={[{ value: "", label: "-- Select Department --" }, ...depts.map(d => ({ value: d.name, label: d.name }))]} />
        <Select label="Assign Teacher *" value={form.teacherId} onChange={e => setForm(f => ({ ...f, teacherId: e.target.value }))}
